import modal
import json
import os

app = modal.App("warm-pool-server")
image = modal.Image.debian_slim()

@app.cls(image=image, keep_warm=1)
class WarmServer:
    @modal.enter()
    def setup(self):
        self.data_store = {}
        self.request_count = 0
        print("WarmServer setup complete")

    @modal.method()
    def handle_request(self, key, value):
        self.data_store[key] = value
        self.request_count += 1
        return {"status": "success", "key": key, "value": value}

    @modal.method()
    def get_stats(self):
        return {
            "total_requests": self.request_count,
            "stored_keys": list(self.data_store.keys())
        }

@app.local_entrypoint()
def main():
    server = WarmServer()

    # Call handle_request twice
    print("Calling handle_request with ('name', 'Alice')...")
    server.handle_request.remote("name", "Alice")

    print("Calling handle_request with ('role', 'engineer')...")
    server.handle_request.remote("role", "engineer")

    # Call get_stats
    print("Fetching stats...")
    stats = server.get_stats.remote()
    print(f"Stats: {stats}")

    # Write stats to JSON file
    stats_path = "/home/user/modal_project/server_stats.json"
    with open(stats_path, "w") as f:
        json.dump(stats, f, indent=4)
    print(f"Stats written to {stats_path}")

